`, "",{"version":3,"sources":["webpack://./src/图片托管/管理面板.vue"],"names":[],"mappings":"AAoaA,sCACE,YACF,CAGA,sCACE,YAAa,CACb,QAAS,CACT,gBAAiB,CACjB,YAAa,CACb,gEAAqE,CACrE,iBAAkB,CAClB,kDACF,CAEA,0CACE,YAAa,CACb,kBAAmB,CACnB,OAAQ,CACR,cAAe,CACf,WACF,CAEA,4CACE,cAAe,CACf,WACF,CAGA,wCACE,gBAAiB,CACjB,YAAa,CACb,qBAAsB,CACtB,OACF,CAEA,uCACE,YAAa,CACb,kBAAmB,CACnB,OACF,CAEA,qDACE,cAAe,CACf,WACF,CAEA,0CACE,YAAa,CACb,kBAAmB,CACnB,QAAS,CACT,cACF,CAEA,+CACE,YAAa,CACb,kBAAmB,CACnB,OAAQ,CACR,cAAe,CACf,cACF,CAEA,yCACE,mDAAqD,CACrD,iBAAkB,CAClB,YAAa,CACb,iBAAkB,CAClB,cAAe,CACf,wBAAyB,CACzB,YAAa,CACb,qBAAsB,CACtB,kBAAmB,CACnB,OAAQ,CACR,WACF,CAEA,gGAEE,gDAAkD,CAClD,SACF,CAEA,2CACE,cACF,CAEA,2CACE,YAAa,CACb,QAAS,CACT,aAAc,CACd,yDAA2D,CAC3D,kBACF,CAEA,8CACE,UAAW,CACX,WAAY,CACZ,aAAc,CACd,iBAAkB,CAClB,eAAgB,CAChB,cAAe,CACf,wBACF,CAEA,oDACE,WACF,CAEA,kDACE,UAAW,CACX,WAAY,CACZ,gBACF,CAEA,2CACE,MAAO,CACP,WAAY,CACZ,YAAa,CACb,qBAAsB,CACtB,OACF,CAEA,2CACE,YAAa,CACb,kBAAmB,CACnB,OAAQ,CACR,cACF,CAEA,gDACE,eAAgB,CAChB,sBAAuB,CACvB,kBACF,CAEA,8CACE,YAAa,CACb,OACF,CAEA,yCACE,cAAe,CACf,WAAY,CACZ,wBAAyB,CACzB,cACF,CAEA,+CACE,SACF,CAGA,wCACE,cAAe,CACf,KAAM,CACN,MAAO,CACP,WAAY,CACZ,YAAa,CACb,2BAA+B,CAC/B,aAAc,CACd,YAAa,CACb,kBAAmB,CACnB,sBAAuB,CACvB,cACF,CAEA,kDACE,iBAAkB,CAClB,cAAe,CACf,eAAgB,CAChB,cACF,CAEA,sDACE,cAAe,CACf,eAAgB,CAChB,kBAAmB,CACnB,iBAAkB,CAClB,qCACF,CAEA,6CACE,iBAAkB,CAClB,cAAe,CACf,UAAW,CACX,YAAa,CACb,qBAAsB,CACtB,OACF,CAEA,8CACE,iBAAkB,CAClB,SAAU,CACV,WAAY,CACZ,cAAe,CACf,UAAW,CACX,0BAA8B,CAC9B,iBAAkB,CAClB,UAAW,CACX,WAAY,CACZ,YAAa,CACb,kBAAmB,CACnB,sBAAuB,CACvB,cAAe,CACf,2BACF,CAEA,oDACE,gCACF","sourcesContent":["<template>\n  <div class=\"image-hosting-panel\">\n    <div class=\"image-hosting_header\">\n      <b><i class=\"fa-solid fa-images\"></i> 图片托管</b>\n    </div>\n        <!-- 当前角色卡名 -->\n        <div class=\"image-hosting_block flex-container flexFlowColumn\">\n          <small>当前角色卡: <b>{{ characterName }}</b></small>\n        </div>\n\n        <!-- 使用统计 -->\n        <div v-if=\"images.length > 0\" class=\"image-hosting_stats\">\n          <div class=\"image-hosting_stat-item\">\n            <i class=\"fa-solid fa-images\"></i>\n            <span>{{ images.length }} 张</span>\n          </div>\n          <div class=\"image-hosting_stat-item\">\n            <i class=\"fa-solid fa-hard-drive\"></i>\n            <span>{{ formatSize(totalSize) }}</span>\n          </div>\n          <div class=\"image-hosting_stat-item\">\n            <i class=\"fa-solid fa-server\"></i>\n            <span>本地 {{ localCount }} / 嵌入 {{ embeddedCount }}</span>\n          </div>\n        </div>\n\n        <!-- 存储模式 -->\n        <div class=\"image-hosting_block flex-container\" style=\"align-items: center; gap: 8px\">\n          <label>存储模式</label>\n          <select v-model=\"settings.storage_mode\" class=\"text_pole\" style=\"height: 28px; flex: 1\">\n            <option value=\"local\">本地文件 (需额外分享压缩包)</option>\n            <option value=\"embedded\">嵌入角色卡 (导出卡片时自动包含)</option>\n          </select>\n        </div>\n\n        <!-- 上传区域 -->\n        <div class=\"image-hosting_block\">\n          <div\n            class=\"image-hosting_dropzone\"\n            :class=\"{ 'image-hosting_dropzone--active': isDragging }\"\n            @dragover.prevent=\"isDragging = true\"\n            @dragleave.prevent=\"isDragging = false\"\n            @drop.prevent=\"handleDrop\"\n            @click=\"triggerFileInput\"\n          >\n            <i class=\"fa-solid fa-cloud-arrow-up\"></i>\n            <span>{{ uploading ? `上传中 (${uploadProgress})...` : '拖拽图片到此处, 或点击选择' }}</span>\n          </div>\n          <input\n            ref=\"fileInputRef\"\n            type=\"file\"\n            accept=\"image/*\"\n            multiple\n            style=\"display: none\"\n            @change=\"handleFileSelect\"\n          />\n        </div>\n\n        <!-- 设置区域 -->\n        <div class=\"image-hosting_block flex-container\">\n          <input v-model=\"settings.auto_compress\" type=\"checkbox\" />\n          <label>上传时压缩/转 WebP</label>\n        </div>\n        <div v-if=\"settings.auto_compress\" class=\"image-hosting_block flex-container\">\n          <label>压缩质量: {{ Math.round(settings.compress_quality * 100) }}%</label>\n          <input\n            v-model.number=\"settings.compress_quality\"\n            type=\"range\"\n            min=\"0.1\"\n            max=\"1\"\n            step=\"0.05\"\n            style=\"flex: 1\"\n          />\n        </div>\n\n        <!-- 导入导出按钮 (仅 local 模式) -->\n        <div v-if=\"settings.storage_mode === 'local'\" class=\"image-hosting_block flex-container\">\n          <input class=\"menu_button\" type=\"submit\" value=\"导出图片包\" @click=\"handleExport\" />\n          <input class=\"menu_button\" type=\"submit\" value=\"导入图片包\" @click=\"handleImport\" />\n        </div>\n        <div v-else class=\"image-hosting_block\">\n          <small style=\"opacity: 0.6\">\n            <i class=\"fa-solid fa-circle-info\"></i>\n            嵌入模式: 图片数据跟随角色卡导出/导入，无需额外压缩包\n          </small>\n        </div>\n\n        <hr class=\"sysHR\" />\n\n        <!-- 搜索栏 + 批量操作 -->\n        <div v-if=\"images.length > 0\" class=\"image-hosting_toolbar\">\n          <div class=\"image-hosting_search\">\n            <i class=\"fa-solid fa-magnifying-glass\"></i>\n            <input\n              v-model=\"searchQuery\"\n              class=\"text_pole\"\n              placeholder=\"搜索图片名称...\"\n              style=\"flex: 1; height: 26px; font-size: 12px\"\n            />\n            <i\n              v-if=\"searchQuery\"\n              class=\"fa-solid fa-xmark image-hosting_icon-btn\"\n              @click=\"searchQuery = ''\"\n            ></i>\n          </div>\n          <div class=\"image-hosting_batch-bar\">\n            <label class=\"image-hosting_checkbox-label\">\n              <input type=\"checkbox\" :checked=\"isAllSelected\" @change=\"toggleSelectAll\" />\n              <span>{{ isAllSelected ? '取消全选' : '全选' }}</span>\n            </label>\n            <template v-if=\"selectedSet.size > 0\">\n              <small style=\"opacity: 0.7\">已选 {{ selectedSet.size }} 张</small>\n              <i\n                class=\"fa-solid fa-trash-can image-hosting_icon-btn\"\n                title=\"批量删除\"\n                style=\"color: var(--SmartThemeQuoteColor, #e74c3c)\"\n                @click=\"handleBatchDelete\"\n              ></i>\n              <i\n                class=\"fa-solid fa-copy image-hosting_icon-btn\"\n                title=\"批量复制调用代码\"\n                @click=\"handleBatchCopyCode\"\n              ></i>\n            </template>\n          </div>\n        </div>\n\n        <!-- 图片列表 -->\n        <div v-if=\"images.length === 0\" class=\"image-hosting_block\">\n          <small style=\"opacity: 0.6\">暂无图片, 请上传</small>\n        </div>\n        <div v-else-if=\"filteredImages.length === 0\" class=\"image-hosting_block\">\n          <small style=\"opacity: 0.6\">没有匹配「{{ searchQuery }}」的图片</small>\n        </div>\n        <div v-for=\"image in filteredImages\" :key=\"image.storageName\" class=\"image-hosting_image-item\">\n          <input\n            type=\"checkbox\"\n            :checked=\"selectedSet.has(image.storageName)\"\n            @change=\"toggleSelect(image.storageName)\"\n            style=\"flex-shrink: 0\"\n          />\n          <div class=\"image-hosting_image-preview\" @click=\"openPreview(image)\">\n            <img :src=\"image.url\" :alt=\"image.display_name\" loading=\"lazy\" />\n          </div>\n          <div class=\"image-hosting_image-info\">\n            <div class=\"image-hosting_image-name\">\n              <template v-if=\"editingName !== image.storageName\">\n                <span :title=\"image.display_name\">{{ image.display_name }}</span>\n                <i\n                  class=\"fa-solid fa-pen-to-square image-hosting_icon-btn\"\n                  title=\"重命名\"\n                  @click=\"startRename(image.storageName, image.display_name)\"\n                ></i>\n              </template>\n              <template v-else>\n                <input\n                  v-model=\"editNameValue\"\n                  class=\"text_pole\"\n                  style=\"flex: 1; height: 24px; font-size: 12px\"\n                  @keyup.enter=\"confirmRename(image.storageName)\"\n                  @keyup.escape=\"cancelRename\"\n                />\n                <i\n                  class=\"fa-solid fa-check image-hosting_icon-btn\"\n                  title=\"确认\"\n                  @click=\"confirmRename(image.storageName)\"\n                ></i>\n                <i\n                  class=\"fa-solid fa-xmark image-hosting_icon-btn\"\n                  title=\"取消\"\n                  @click=\"cancelRename\"\n                ></i>\n              </template>\n            </div>\n            <small style=\"opacity: 0.6\">\n              {{ formatSize(image.size) }} · {{ image.mime_type }}\n              <span v-if=\"image.storage === 'embedded'\" style=\"color: var(--SmartThemeQuoteColor, #3498db)\">\n                · 嵌入\n              </span>\n            </small>\n            <div class=\"image-hosting_image-actions\">\n              <i\n                class=\"fa-solid fa-copy image-hosting_icon-btn\"\n                title=\"复制调用代码\"\n                @click=\"copyCode(image.display_name)\"\n              ></i>\n              <i\n                class=\"fa-solid fa-trash-can image-hosting_icon-btn\"\n                title=\"删除\"\n                style=\"color: var(--SmartThemeQuoteColor, #e74c3c)\"\n                @click=\"handleDelete(image.storageName, image.display_name)\"\n              ></i>\n            </div>\n          </div>\n        </div>\n\n        <hr class=\"sysHR\" />\n\n    <!-- 大图预览浮层 -->\n    <Teleport to=\"body\">\n      <div v-if=\"previewImage\" class=\"image-hosting_overlay\" @click.self=\"closePreview\">\n        <div class=\"image-hosting_preview-container\">\n          <img :src=\"previewImage.url\" :alt=\"previewImage.display_name\" />\n          <div class=\"image-hosting_preview-info\">\n            <span>{{ previewImage.display_name }}</span>\n            <small>{{ formatSize(previewImage.size) }} · {{ previewImage.mime_type }}</small>\n          </div>\n          <i class=\"fa-solid fa-xmark image-hosting_preview-close\" @click=\"closePreview\"></i>\n        </div>\n      </div>\n    </Teleport>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { storeToRefs } from 'pinia';\nimport { useSettingsStore } from './settings';\nimport { useImageStore, type ImageMeta } from './image-store';\nimport { exportImages, importImages } from './export-import';\n\ntype ImageItem = { storageName: string; url: string } & ImageMeta;\n\nconst { settings } = storeToRefs(useSettingsStore());\nconst imageStore = useImageStore();\n\nconst images = computed(() => imageStore.getAllImages());\nconst characterName = ref(substitudeMacros('{{char}}') || '未选择');\n\n// 搜索\nconst searchQuery = ref('');\nconst filteredImages = computed(() => {\n  if (!searchQuery.value.trim()) return images.value;\n  const q = searchQuery.value.trim().toLowerCase();\n  return images.value.filter(img =>\n    img.display_name.toLowerCase().includes(q) ||\n    img.original_name.toLowerCase().includes(q),\n  );\n});\n\n// 使用统计\nconst totalSize = computed(() => _.sumBy(images.value, 'size'));\nconst localCount = computed(() => images.value.filter(i => i.storage === 'local').length);\nconst embeddedCount = computed(() => images.value.filter(i => i.storage === 'embedded').length);\n\n// 批量选择\nconst selectedSet = ref(new Set<string>());\nconst isAllSelected = computed(() =>\n  filteredImages.value.length > 0 && filteredImages.value.every(img => selectedSet.value.has(img.storageName)),\n);\n\nfunction toggleSelect(storageName: string) {\n  const s = new Set(selectedSet.value);\n  if (s.has(storageName)) s.delete(storageName);\n  else s.add(storageName);\n  selectedSet.value = s;\n}\n\nfunction toggleSelectAll() {\n  if (isAllSelected.value) {\n    selectedSet.value = new Set();\n  } else {\n    selectedSet.value = new Set(filteredImages.value.map(img => img.storageName));\n  }\n}\n\n// 上传状态\nconst uploading = ref(false);\nconst uploadProgress = ref('');\nconst isDragging = ref(false);\nconst fileInputRef = ref<HTMLInputElement>();\n\n// 重命名状态\nconst editingName = ref<string | null>(null);\nconst editNameValue = ref('');\n\n// 大图预览状态\nconst previewImage = ref<ImageItem | null>(null);\n\n// 监听角色卡切换\neventOn(tavern_events.CHAT_CHANGED, () => {\n  characterName.value = substitudeMacros('{{char}}') || '未选择';\n  imageStore.reload();\n  selectedSet.value = new Set();\n  searchQuery.value = '';\n});\n\nfunction triggerFileInput() {\n  fileInputRef.value?.click();\n}\n\nasync function uploadFiles(files: FileList | File[]) {\n  uploading.value = true;\n  let completed = 0;\n  const total = files.length;\n\n  for (const file of files) {\n    if (!file.type.startsWith('image/')) {\n      toastr.warning(`'${file.name}' 不是图片文件, 已跳过`);\n      completed++;\n      continue;\n    }\n\n    try {\n      uploadProgress.value = `${completed + 1}/${total}`;\n      await imageStore.upload(file);\n      completed++;\n    } catch (err) {\n      console.error(`上传 '${file.name}' 失败:`, err);\n      toastr.error(`上传 '${file.name}' 失败`);\n      completed++;\n    }\n  }\n\n  uploading.value = false;\n  toastr.success(`成功上传 ${completed}/${total} 张图片`);\n}\n\nfunction handleDrop(event: DragEvent) {\n  isDragging.value = false;\n  const files = event.dataTransfer?.files;\n  if (files && files.length > 0) {\n    uploadFiles(files);\n  }\n}\n\nfunction handleFileSelect(event: Event) {\n  const target = event.target as HTMLInputElement;\n  if (target.files && target.files.length > 0) {\n    uploadFiles(target.files);\n    target.value = '';\n  }\n}\n\nfunction startRename(storageName: string, currentName: string) {\n  editingName.value = storageName;\n  editNameValue.value = currentName;\n}\n\nfunction confirmRename(storageName: string) {\n  if (editNameValue.value.trim()) {\n    imageStore.rename(storageName, editNameValue.value.trim());\n  }\n  editingName.value = null;\n}\n\nfunction cancelRename() {\n  editingName.value = null;\n}\n\nasync function handleDelete(storageName: string, displayName: string) {\n  const result = await SillyTavern.callGenericPopup(\n    `确定要删除图片「${displayName}」吗？`,\n    SillyTavern.POPUP_TYPE.CONFIRM,\n  );\n  if (result === SillyTavern.POPUP_RESULT.AFFIRMATIVE) {\n    await imageStore.remove(storageName);\n    selectedSet.value.delete(storageName);\n    toastr.success(`已删除「${displayName}」`);\n  }\n}\n\nasync function handleBatchDelete() {\n  const count = selectedSet.value.size;\n  if (count === 0) return;\n  const result = await SillyTavern.callGenericPopup(\n    `确定要删除选中的 ${count} 张图片吗？`,\n    SillyTavern.POPUP_TYPE.CONFIRM,\n  );\n  if (result === SillyTavern.POPUP_RESULT.AFFIRMATIVE) {\n    const names = [...selectedSet.value];\n    for (const name of names) {\n      await imageStore.remove(name);\n    }\n    selectedSet.value = new Set();\n    toastr.success(`已删除 ${names.length} 张图片`);\n  }\n}\n\nfunction copyCode(displayName: string) {\n  const code = `ImageHosting.getImageUrl('${displayName}')`;\n  navigator.clipboard.writeText(code).then(() => {\n    toastr.success('已复制调用代码');\n  });\n}\n\nfunction handleBatchCopyCode() {\n  const codes = filteredImages.value\n    .filter(img => selectedSet.value.has(img.storageName))\n    .map(img => `ImageHosting.getImageUrl('${img.display_name}')`)\n    .join('\\n');\n  navigator.clipboard.writeText(codes).then(() => {\n    toastr.success(`已复制 ${selectedSet.value.size} 条调用代码`);\n  });\n}\n\nfunction formatSize(bytes: number): string {\n  if (bytes < 1024) return `${bytes} B`;\n  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;\n  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;\n}\n\n// 大图预览\nfunction openPreview(image: ImageItem) {\n  previewImage.value = image;\n}\n\nfunction closePreview() {\n  previewImage.value = null;\n}\n\nasync function handleExport() {\n  await exportImages();\n}\n\nasync function handleImport() {\n  await importImages();\n}\n</script>\n\n<style scoped>\n.image-hosting_block {\n  margin: 5px 0;\n}\n\n/* 使用统计 */\n.image-hosting_stats {\n  display: flex;\n  gap: 12px;\n  padding: 8px 10px;\n  margin: 5px 0;\n  background: var(--SmartThemeBlurTintColor, rgba(255, 255, 255, 0.05));\n  border-radius: 6px;\n  border: 1px solid var(--SmartThemeBorderColor, #333);\n}\n\n.image-hosting_stat-item {\n  display: flex;\n  align-items: center;\n  gap: 5px;\n  font-size: 12px;\n  opacity: 0.8;\n}\n\n.image-hosting_stat-item i {\n  font-size: 11px;\n  opacity: 0.6;\n}\n\n/* 搜索栏 + 批量工具栏 */\n.image-hosting_toolbar {\n  margin: 5px 0 8px;\n  display: flex;\n  flex-direction: column;\n  gap: 6px;\n}\n\n.image-hosting_search {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n}\n\n.image-hosting_search > i:first-child {\n  font-size: 12px;\n  opacity: 0.5;\n}\n\n.image-hosting_batch-bar {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  font-size: 12px;\n}\n\n.image-hosting_checkbox-label {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  cursor: pointer;\n  font-size: 12px;\n}\n\n.image-hosting_dropzone {\n  border: 2px dashed var(--SmartThemeBorderColor, #555);\n  border-radius: 8px;\n  padding: 20px;\n  text-align: center;\n  cursor: pointer;\n  transition: all 0.2s ease;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 8px;\n  opacity: 0.7;\n}\n\n.image-hosting_dropzone:hover,\n.image-hosting_dropzone--active {\n  border-color: var(--SmartThemeQuoteColor, #3498db);\n  opacity: 1;\n}\n\n.image-hosting_dropzone i {\n  font-size: 24px;\n}\n\n.image-hosting_image-item {\n  display: flex;\n  gap: 10px;\n  padding: 8px 0;\n  border-bottom: 1px solid var(--SmartThemeBorderColor, #333);\n  align-items: center;\n}\n\n.image-hosting_image-preview {\n  width: 50px;\n  height: 50px;\n  flex-shrink: 0;\n  border-radius: 4px;\n  overflow: hidden;\n  cursor: pointer;\n  transition: opacity 0.15s;\n}\n\n.image-hosting_image-preview:hover {\n  opacity: 0.8;\n}\n\n.image-hosting_image-preview img {\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n}\n\n.image-hosting_image-info {\n  flex: 1;\n  min-width: 0;\n  display: flex;\n  flex-direction: column;\n  gap: 2px;\n}\n\n.image-hosting_image-name {\n  display: flex;\n  align-items: center;\n  gap: 5px;\n  font-size: 13px;\n}\n\n.image-hosting_image-name span {\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.image-hosting_image-actions {\n  display: flex;\n  gap: 8px;\n}\n\n.image-hosting_icon-btn {\n  cursor: pointer;\n  opacity: 0.6;\n  transition: opacity 0.15s;\n  font-size: 13px;\n}\n\n.image-hosting_icon-btn:hover {\n  opacity: 1;\n}\n\n/* 大图预览浮层 */\n.image-hosting_overlay {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: 100vw;\n  height: 100vh;\n  background: rgba(0, 0, 0, 0.85);\n  z-index: 99999;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n}\n\n.image-hosting_preview-container {\n  position: relative;\n  max-width: 90vw;\n  max-height: 90vh;\n  cursor: default;\n}\n\n.image-hosting_preview-container img {\n  max-width: 90vw;\n  max-height: 85vh;\n  object-fit: contain;\n  border-radius: 8px;\n  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.5);\n}\n\n.image-hosting_preview-info {\n  text-align: center;\n  margin-top: 8px;\n  color: #ccc;\n  display: flex;\n  flex-direction: column;\n  gap: 2px;\n}\n\n.image-hosting_preview-close {\n  position: absolute;\n  top: -12px;\n  right: -12px;\n  font-size: 20px;\n  color: #fff;\n  background: rgba(0, 0, 0, 0.6);\n  border-radius: 50%;\n  width: 32px;\n  height: 32px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  transition: background 0.15s;\n}\n\n.image-hosting_preview-close:hover {\n  background: rgba(255, 255, 255, 0.2);\n}\n</style>\n"],"sourceRoot":""}]);
